            // Backspace
            Button(
                onClick = onBackspace,
                modifier = Modifier.size(70.dp),
                shape = CircleShape,
                colors = ButtonDefaults.buttonColors(
                    containerColor = Color(0xFF0f3460)
                )
            ) {
                Text(
                    text = "⌫",
                    fontSize = 24.sp,
                    color = Color.White
                )
            }
        }
    }
}

